  id: string;
  name: string;
  email: string;
  role: string | null;
};

type SupervisorComboboxProps = {
  users: UserOption[];
  value: string | null;
  onChange: (value: string | null) => void;
  excludeUserId?: string;
  disabled?: boolean;
  required?: boolean;
};
```

- Renders a `Popover` + `Command` (cmdk) combobox
- Supports `required` — when true, hides the "None" option
- Supports `excludeUserId` — filters out a user (e.g., the user being edited can't be their own supervisor)
- Displays role next to name using `ROLE_DISPLAY_NAMES`
- Value is `string | null` (null = no supervisor)
- Search by name or email

---

## 4. LogoUpload — `/home/aditya/projects/alpauls-ats/src/components/logo-upload.tsx`

```ts
type LogoUploadProps = {
  value: string | null | undefined;
  onChange: (url: string | null) => void;
};
```

- Accepts PNG, JPEG, SVG, WebP (max 2MB)
- On select, calls `rpc.client.getUploadUrl` to get a presigned URL, then `PUT`s the file
- On success, calls `onChange(publicUrl)`
- Shows preview with "Remove" button when value exists, otherwise a dashed drop zone
- Has drag-and-drop support

